using System.Collections;
using UnityEngine;

/// <summary>Toca um efeito sonoro (SE) uma vez, através de AudioManager.</summary>
[System.Serializable]
public class Action_PlaySE : NpcAction
{
    public AudioClip clip;

    [Range(0f, 1f)]
    [Tooltip("Volume relativo deste som (multiplicado pelo volume de SE nas opções).")]
    public float volume = 1f;

    [Tooltip("1 = altura normal. Valores diferentes mudam o tom do som.")]
    public float pitch = 1f;

    public override IEnumerator Execute(NpcController npc)
    {
        if (clip != null) AudioManager.Instance?.PlaySE(clip, volume, pitch);
        yield break;
    }
}

/// <summary>Muda a música de fundo (BGM), com transição suave (crossfade). Clip vazio = parar (ver Action_StopBGM).</summary>
[System.Serializable]
public class Action_PlayBGM : NpcAction
{
    public AudioClip clip;

    [Tooltip("Duração da transição (em segundos).")]
    public float fadeTime = 1.5f;

    public bool loop = true;

    [Tooltip("Se activo, espera a transição terminar antes de avançar para a próxima ação.")]
    public bool waitForFade;

    public override IEnumerator Execute(NpcController npc)
    {
        AudioManager.Instance?.PlayBGM(clip, fadeTime, loop);
        if (waitForFade && fadeTime > 0f) yield return NpcActionUtil.Wait(fadeTime);
    }
}

